import React, { useState, useRef, useEffect } from 'react';
import { CiCirclePlus } from "react-icons/ci";
import './calendar_modal.css';

const CalendarModal = ({ isOpen, onClose, onConfirm }) => {
    const [selectedDateTime, setSelectedDateTime] = useState('');
    const [selectedFiles, setSelectedFiles] = useState([]);
    const [slideInterval, setSlideInterval] = useState(4);
    const [timerName, setTimerName] = useState('');
    const [intervalUnit, setIntervalUnit] = useState('seconds'); // 'seconds' или 'hours'
    const [isCalendarVisible, setIsCalendarVisible] = useState(false); // Control calendar block visibility
    const [isTimerClockVisible, setIsTimerClockVisible] = useState(true); // Control timer clock block visibility
    const [isStopwatchVisible, setIsStopwatchVisible] = useState(false); // Control stopwatch block visibility
    const [stopwatchName, setStopwatchName] = useState(''); // Stopwatch name
    const fileInputRef = useRef(null);
    const timerClockRef = useRef(null);
    const calendarRef = useRef(null);
    const stopwatchRef = useRef(null);

    // Очистка всех полей при закрытии модального окна
    useEffect(() => {
        if (!isOpen) {
            // Очищаем все состояния
            setSelectedDateTime('');
            setSelectedFiles([]);
            setSlideInterval(4);
            setTimerName('');
            setIntervalUnit('seconds');
            setIsCalendarVisible(false);
            setIsTimerClockVisible(true);
            setIsStopwatchVisible(false);
            setStopwatchName('');
        }
    }, [isOpen]);

    // Обработчик клика вне блока timer_second_clock
    useEffect(() => {

        const handleClickOutside = (event) => {
            if (timerClockRef.current && !timerClockRef.current.contains(event.target)) {
                onClose();
            }
        };

        if (isOpen) {
            document.addEventListener('mousedown', handleClickOutside);
        }

        return () => {
            document.removeEventListener('mousedown', handleClickOutside);
        };
    }, [isOpen, onClose]);

    // Обработчик клика вне блока block_calendar
    useEffect(() => {
        const handleClickOutsideCalendar = (event) => {
            if (calendarRef.current && !calendarRef.current.contains(event.target)) {
                onClose();
            }
        };

        if (isOpen && isCalendarVisible) {
            document.addEventListener('mousedown', handleClickOutsideCalendar);
        }

        return () => {
            document.removeEventListener('mousedown', handleClickOutsideCalendar);
        };
    }, [isOpen, isCalendarVisible, onClose]);

    // Обработчик клика вне блока секундомера
    useEffect(() => {
        const handleClickOutsideStopwatch = (event) => {
            if (stopwatchRef.current && !stopwatchRef.current.contains(event.target)) {
                onClose();
            }
        };

        if (isOpen && isStopwatchVisible) {
            document.addEventListener('mousedown', handleClickOutsideStopwatch);
        }

        return () => {
            document.removeEventListener('mousedown', handleClickOutsideStopwatch);
        };
    }, [isOpen, isStopwatchVisible, onClose]);

    const handleDateTimeChange = (e) => {
        setSelectedDateTime(e.target.value);
    };



    const handleRemoveFile = (indexToRemove) => {
        setSelectedFiles(prev => {
            const newFiles = prev.filter((_, index) => index !== indexToRemove);
            // Clean up URL object for removed file to prevent memory leaks
            const removedFile = prev[indexToRemove];
            if (removedFile && removedFile.url) {
                URL.revokeObjectURL(removedFile.url);
            }
            return newFiles;
        });
    };

    const handleAddFileClick = () => {
        if (fileInputRef.current) {
            fileInputRef.current.click();
        }
    };

    const handleFileInputChange = (event) => {
        const files = Array.from(event.target.files);
        files.forEach(file => {
            if (file) {
                try {
                    // Ensure file has URL for preview
                    if (!file.url) {
                        file.url = URL.createObjectURL(file);
                    }
                    setSelectedFiles(prev => [...prev, file]);
                } catch (error) {
                    console.error('Error processing file:', error);
                }
            }
        });
        // Reset the input value to allow selecting the same file again
        event.target.value = '';
    };

    const handleConfirm = () => {

        if (selectedDateTime) {
            // Конвертируем интервал в секунды если выбран часовой формат
            const intervalInSeconds = intervalUnit === 'hours' ? slideInterval * 3600 : slideInterval;
            onConfirm(selectedDateTime, selectedFiles, intervalInSeconds, timerName);
            onClose();
        }
    };



    const handleBackClick = () => {
        setTimeout(() => {
            onClose();
        }, 50);
    };

    const handleTimerClick = () => {
        setIsCalendarVisible(true);
        setIsTimerClockVisible(false);
    };

    const handleStopwatchClick = () => {
        setIsStopwatchVisible(true);
        setIsTimerClockVisible(false);
    };

    const handleStopwatchStart = () => {
        // Создаем объект секундомера (даже с пустым именем)
        const stopwatchData = {
            type: 'stopwatch',
            name: stopwatchName || '', // Если имя пустое, используем значение по умолчанию
            startTime: new Date().toISOString(),
            isActive: true
        };
        onConfirm(null, [], 0, stopwatchName || '', stopwatchData);
        onClose();
    };

    if (!isOpen) return null;

    return (
        <div className='modal_calendarm'>


            {isTimerClockVisible && (
                <div className='timer_second_clock' ref={timerClockRef}>
                    <div className='grid_item'>

                        <div className='set_timer' onClick={() => setTimeout(() => handleTimerClick(), 40)}
                        >
                            Таймер
                        </div>
                        <div className='set_second_clock' onClick={() => setTimeout(() => handleStopwatchClick(), 40)}>
                            Секундомер
                        </div>
                        <div className='back_cancel' onClick={handleBackClick}>
                            Отмена
                        </div>
                    </div>
                </div>
            )}


            {isCalendarVisible && (
                <div className='block_calendar' ref={calendarRef} onClose={onClose} >
                    <h4 className='timer_span'>Таймер</h4>

                    {/* Инпут для названия таймера */}
                    <div className="timer_name_input">
                        <label htmlFor="timer-name">Название</label>
                        <input
                            id="timer-name"
                            type="text"
                            value={timerName}
                            onChange={(e) => setTimerName(e.target.value)}
                            className="calendar_modal_name"
                            placeholder="Название таймера"
                        />
                    </div>

                    {/* Инпут для даты и времени */}
                    <div className="datetime_input">
                        <label htmlFor="datetime">Дата и время</label>
                        <input
                            id="datetime"
                            type="datetime-local"
                            value={selectedDateTime}
                            onChange={handleDateTimeChange}
                            className="calendar_modal_input"
                            placeholder="Выбрать дату и время"
                        />
                    </div>

                    {/* Инпут для интервала с переключателем единиц измерения */}
                    {selectedFiles.length > 1 && (
                        <div className="slide_interval_input">
                            <label htmlFor="slide-interval">Интервал смены слайдов</label>
                            <div className="interval_input_container">
                                <input
                                    id="slide-interval"
                                    type="number"
                                    min="1"
                                    max={intervalUnit === 'hours' ? 24 : 3600}
                                    value={slideInterval}
                                    onChange={(e) => setSlideInterval(parseInt(e.target.value) || 1)}
                                    className="calendar_modal_input interval_number"
                                />
                                <div className="interval_unit_selector">
                                    <button
                                        type="button"
                                        className={`unit_button ${intervalUnit === 'seconds' ? 'active' : ''}`}
                                        onClick={() => setIntervalUnit('seconds')}
                                    >
                                        сек
                                    </button>
                                    <button
                                        type="button"
                                        className={`unit_button ${intervalUnit === 'hours' ? 'active' : ''}`}
                                        onClick={() => setIntervalUnit('hours')}
                                    >
                                        час
                                    </button>
                                </div>
                            </div>
                            <small className="interval_help">
                                {intervalUnit === 'seconds'
                                    ? 'Интервал в секундах (1-3600)'
                                    : 'Интервал в часах (1-24)'
                                }
                            </small>
                        </div>
                    )}

                    <div className="calendar_modal_buttons">
                        <div className='back_cancel' onClick={() => setTimeout(() => onClose(), 50)}>Отмена</div>
                        <CiCirclePlus className='add_timer_pictures' onClick={handleAddFileClick} />
                        <button className='start' onClick={() => setTimeout(() => handleConfirm(), 50)} disabled={!selectedDateTime}>Старт</button>
                    </div>

                    {selectedFiles.length > 0 && (
                        <div className="selected_files_preview">
                            <h5>Выбранные файлы:</h5>
                            <div className="files_list">
                                {selectedFiles.map((file, index) => (
                                    <div key={index} className="file_item">
                                        <div className="file_preview_container">
                                            {file.type.startsWith('image/') ? (
                                                <img src={file.url} alt={file.name} className="file_preview_small" />
                                            ) : file.type.startsWith('video/') ? (
                                                <video src={file.url} className="file_preview_small" />
                                            ) : (
                                                <div className="file_icon">📄</div>
                                            )}
                                            <button
                                                className="remove_file_btn"
                                                onClick={() => handleRemoveFile(index)}
                                                title="Удалить файл"
                                            >
                                                ×
                                            </button>
                                        </div>
                                        <span className="file_name">{file.name}</span>
                                    </div>
                                ))}
                            </div>
                        </div>
                    )}
                </div>
            )}

            {isStopwatchVisible && (
                <div className='block_calendar' ref={stopwatchRef} >
                    <h4 className='timer_span'>Секундомер</h4>

                    {/* Инпут для названия секундомера */}
                    <div className="timer_name_input">
                        <label htmlFor="stopwatch-name">Название</label>
                        <input
                            id="stopwatch-name"
                            type="text"
                            value={stopwatchName}
                            onChange={(e) => setStopwatchName(e.target.value)}
                            className="calendar_modal_name"
                            placeholder="Название секундомера"
                        />
                    </div>

                    <div className="calendar_modal_buttons">
                        <div className='back_cancel' onClick={() => setTimeout(() => onClose(), 50)}>Отмена</div>
                        <button className='start' onClick={() => setTimeout(() => handleStopwatchStart(), 50)}>Старт</button>
                    </div>
                </div>
            )}

            {/* Hidden file input */}
            <input
                id="calendar-file-input"
                type="file"
                ref={fileInputRef}
                onChange={handleFileInputChange}
                style={{ display: 'none' }}
                accept="image/*,video/*"
                multiple
            />
        </div>
    );
};

export default CalendarModal;
